Here's a complete implementation:

## XAML

```xml
<ContentPage xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
             xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml"
             xmlns:vm="clr-namespace:MyApp.ViewModels"
             xmlns:models="clr-namespace:MyApp.Models"
             x:Class="MyApp.Views.ItemsPage"
             x:DataType="vm:ItemsViewModel">

    <RefreshView IsRefreshing="{Binding IsRefreshing}"
                 Command="{Binding RefreshCommand}">
        <CollectionView ItemsSource="{Binding Items}"
                        SelectionMode="Single"
                        SelectedItem="{Binding CurrentItem, Mode=TwoWay}"
                        SelectionChangedCommand="{Binding ItemSelectedCommand}">
            <CollectionView.ItemTemplate>
                <DataTemplate x:DataType="models:Item">
                    <Grid Padding="12" ColumnDefinitions="48,*" ColumnSpacing="12">
                        <Image Source="{Binding Icon}" WidthRequest="40" HeightRequest="40" />
                        <Label Grid.Column="1" Text="{Binding Name}" VerticalOptions="Center" />
                    </Grid>
                </DataTemplate>
            </CollectionView.ItemTemplate>
            <CollectionView.EmptyView>
                <ContentView>
                    <Label Text="No items found." HorizontalOptions="Center" VerticalOptions="Center" />
                </ContentView>
            </CollectionView.EmptyView>
        </CollectionView>
    </RefreshView>
</ContentPage>
```

## ViewModel

```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;

    [ObservableProperty]
    private Item? currentItem;

    [ObservableProperty]
    private bool isRefreshing;

    public ObservableCollection<Item> Items { get; } = new();

    public ItemsViewModel(IApiService api)
    {
        _api = api;
    }

    [RelayCommand]
    private async Task ItemSelected()
    {
        if (CurrentItem is null) return;

        await Shell.Current.GoToAsync($"detail?id={CurrentItem.Id}");

        // Reset selection so user can re-select the same item later
        CurrentItem = null;
    }

    [RelayCommand]
    private async Task Refresh()
    {
        try
        {
            var data = await _api.GetItemsAsync();
            MainThread.BeginInvokeOnMainThread(() =>
            {
                Items.Clear();
                foreach (var item in data)
                    Items.Add(item);
            });
        }
        finally
        {
            IsRefreshing = false; // Stops the spinner
        }
    }
}
```

## Key bindings explained

| Property | Binding | Why |
|---|---|---|
| `IsRefreshing` | `TwoWay` (default on `RefreshView`) | Set `false` in VM to dismiss spinner |
| `Command` on `RefreshView` | `RefreshCommand` | Triggers `Refresh()` via `[RelayCommand]` |
| `SelectedItem` | `CurrentItem`, **`Mode=TwoWay`** | Sync selection both ways; reset to `null` after nav |
| `SelectionChangedCommand` | `ItemSelectedCommand` | Fires on tap → navigates to detail page |
| `ItemsSource` | `ObservableCollection<Item>` | Auto-updates UI on add/remove |

**Important details:**
- Always set `x:DataType` on both the page and the `DataTemplate` for compiled bindings.
- Use `ObservableCollection<T>`, never `List<T>` — swapping a `List` forces a full re-render.
- Reset `CurrentItem = null` after navigation so the same item can be re-selected.
- Set `IsRefreshing = false` in a `finally` block to guarantee the spinner stops.
- Update collections on the UI thread via `MainThread.BeginInvokeOnMainThread`.
